import java.util.function.Predicate;

public class Main {
  public static void main(String[] args) {
    Predicate<Integer> isPositive = x -> x > 0;
    System.out.println("5 müsbətdir: " + isPositive.test(5));
    System.out.println("-3 müsbətdir: " + isPositive.test(-3));
  }
}
// Çıxış:
// 5 müsbətdir: true
// -3 müsbətdir: false

import java.util.Arrays;
import java.util.List;

public class Main {
  public static void main(String[] args) {
    List<Integer> numbers = Arrays.asList(1, 2, 3, 4, 5);
    numbers.stream()
           .filter(n -> n % 2 == 0)
           .forEach(n -> System.out.println("Cüt ədəd: " + n));
  }
}
// Çıxış:
// Cüt ədəd: 2
// Cüt ədəd: 4

